/// Convert a `kreuzcrawl::CrawlError` error to a `JsValue` string.
#[allow(dead_code)]
fn crawl_error_to_js_value(e: kreuzcrawl::CrawlError) -> wasm_bindgen::JsValue {
    wasm_bindgen::JsValue::from_str(&e.to_string())
}
